static int c_partition1(int arglist, int rest, int th);
static int c_partition1(int arglist, int rest, int th){
int arg1,arg2,arg3,arg4,varX,varY,varL1,varL2,n,body,save1,save2,save3,goal,cont,clause,res;
Jinc_proof(th);
n = Jlength(arglist);
save1 = Jget_wp(th);
save2 = Jget_sp(th);
save3 = Jget_ac(th);
if(n == 4){
arg1 = Jnth(arglist,1);
arg2 = Jnth(arglist,2);
arg3 = Jnth(arglist,3);
arg4 = Jnth(arglist,4);
varX = Jmakevariant(th);
varY = Jmakevariant(th);
varL1 = Jmakevariant(th);
varL2 = Jmakevariant(th);
arg1 = Jnth(arglist,1);
arg2 = Jnth(arglist,2);
arg3 = Jnth(arglist,3);
arg4 = Jnth(arglist,4);
if(Junify_var(arg1,varX,th) == YES && Junify_var(arg2,varY,th) == YES && Junify_var(arg3,varL1,th) == YES && Junify_var(arg4,varL2,th) == YES && 1)
{ //for qsort
          int exec1(int x, int y, int l1, int l2){
              Jinc_proof(th);
              if(x == NIL)
                  return(Jwlist2(l1,l2,th));
              else if(Jsmallerp(Jcar(x),y)){
                  Jinc_proof(th);
                  return(exec1(Jcdr(x),y,Jwlistcons(Jcar(x),l1,th),l2));
              }
              else return(exec1(Jcdr(x),y,l1,Jwlistcons(Jcar(x),l2,th)));
          }
          int x = Jderef(varX,th);
          int y = Jderef(varY,th);
          int res = exec1(Jcdr(x),y,NIL,NIL);
          Junify(varL1,Jcar(res),th);
          Junify(varL2,Jcar(Jcdr(res)),th);
          return(Jexec_all(rest,Jget_sp(th),th)); }

return(Jprove_all(rest,Jget_sp(th),th));
Jset_ac(save3,th);
Junbind(save2,th);
Jset_wp(save1,th);
return(NO);}
}
static int c_qsort1(int arglist, int rest, int th);
static int c_qsort1(int arglist, int rest, int th){
int arg1,arg2,varX,varY,n,body,save1,save2,save3,goal,cont,clause,res;
Jinc_proof(th);
n = Jlength(arglist);
save1 = Jget_wp(th);
save2 = Jget_sp(th);
save3 = Jget_ac(th);
if(n == 2){
arg1 = Jnth(arglist,1);
arg2 = Jnth(arglist,2);
varX = Jmakevariant(th);
varY = Jmakevariant(th);
arg1 = Jnth(arglist,1);
arg2 = Jnth(arglist,2);
if(Junify_var(arg1,varX,th) == YES && Junify_var(arg2,varY,th) == YES && 1)
{ //qsort
          int exec1(int a1){
            int x,l,l1,l2,r1,r2,r;
            Jinc_proof(th);
            l1 = Jmakevariant(th);
            l2 =  Jmakevariant(th);
            r = Jmakevariant(th);
              if(a1 != NIL){
                  x=Jcar(a1);l=Jcdr(a1);
                  Jcall(Jmakecomp("partition1"),Jwcons(a1,Jwlist3(x,l1,l2,th),th),th);
                  r1 =Jcar(exec1(Jderef(l1,th)));
                  r2 =Jcar(exec1(Jderef(l2,th)));
                  Jcall(Jmakesys("append"),Jwlist3(r1,Jwlistcons(x,r2,th),r,th),th);
                  Jinc_proof(th);
                  return(Jwlist1(Jderef(r,th),th));
              }
              else if(a1 == NIL){
                  return(Jwlist1(a1,th));
          }}
          int x = Jderef(varX,th);
          int res = Jcar(exec1(x));
          Junify(varY,res,th);
          return(Jexec_all(rest,Jget_sp(th),th)); }

return(Jprove_all(rest,Jget_sp(th),th));
Jset_ac(save3,th);
Junbind(save2,th);
Jset_wp(save1,th);
return(NO);}
}
